### Configure a Text Field in Payload CMS

Source: https://github.com/payloadcms/payload/blob/main/tools/claude-plugin/skills/payload/reference/FIELDS.md

This example demonstrates how to define a 'text' field in Payload CMS, including configuration options for validation, uniqueness, localization, and admin UI settings. It shows how to set properties like 'required', 'minLength', 'maxLength', 'index', and 'defaultValue'.

```ts
import type { TextField } from 'payload'

const textField: TextField = {
  name: 'title',
  type: 'text',
  required: true,
  unique: true,
  minLength: 5,
  maxLength: 100,
  index: true,
  localized: true,
  defaultValue: 'Default Title',
  validate: (value) => Boolean(value) || 'Required',
  admin: {
    placeholder: 'Enter title...',
    position: 'sidebar',
    condition: (data) => data.showTitle === true,
  },
}
```

